-- Version log entries for the 2026-05-09 release
--
-- Bundles 5 feature slices + assorted UI bug fixes, all already on dev.
-- Insert this against BOTH dev and prod after the prod deploy completes.
--
-- Variables:
--   :env      → 'dev' or 'prod'
--   :version  → the git short SHA shipped (currently 5eb43db on dev; will be the
--               same on prod after deploy.sh + image build).
--   :author   → Bryan's user id (super_admin: 33a7a147-0f15-4017-bb13-36e0b1a8c0a5)
--
-- Usage:
--   psql -h <host> ... -v env="'dev'" -v version="'5eb43db'" -v author="'33a7a147-...'" -f scripts/version-log-2026-05-09-ship.sql

BEGIN;

-- ============================================================================
-- Slice 1 — Report storage refactor (S3-aware blob storage for report PDFs)
-- ============================================================================
INSERT INTO version_log (id, environment, entry_type, title, description, version, created_by)
VALUES (
    gen_random_uuid(),
    :env,
    'refactor',
    'Report PDFs stored via S3-aware BlobStorage (driver-agnostic)',
    E'## What it does\n\nGeneralizes the existing ticket-attachment storage layer (`internal/service/attachment_storage.go`) into a single `BlobStorage` interface that handles BOTH ticket attachments and report PDFs through the same code path. Each saved blob carries a `storage_driver` (`localfs` | `s3`) and `storage_path` so reads can stream from either backend without caller awareness.\n\n## Why\n\nTicket df835d04 surfaced a bug where shared-report PDF downloads silently failed against the prod-side S3 bucket — reports were still writing to local FS while the rest of the system expected S3 in prod. This refactor unifies the storage path and stops the dev/prod divergence.\n\n## Key changes\n\n- `internal/service/attachment_storage.go` → renamed `AttachmentStorage` → `BlobStorage`; takes a per-call `namespace` (e.g. `tickets/<id>` or `reports/<id>`) instead of a hardcoded ticket UUID. Type alias preserved so existing call sites compile.\n- `internal/service/report_service.go` → `generatePDF` now returns `(driver, storagePath, size, error)`; new `OpenPDF(reportID)` for streaming reads; `DeleteReport` deletes the blob alongside the row.\n- `internal/handler/api/report_handler.go` → `ServeReportPDF` (replaces the old `ServeReportFile`), serves at `/api/reports/{reportID}/file`.\n- New env var `REPORT_S3_PREFIX` controls the prod-side S3 layout.\n- Migration `00028_reports_blob_storage.sql` adds `storage_driver` + `storage_path` to `reports` and backfills existing rows from local FS to the new schema.\n\n## Migration\n\n00028 — additive (no breaking schema changes). Backfill is idempotent.\n\n## Tests\n\n- `internal/service/blob_storage_test.go` — localfs round-trip\n- Verified manually on dev: write → read → delete flow on a freshly generated PDF.\n\n## Commits\n\nb979019 → 811025c (8 commits). The runtime-migration-runner gotcha around goose markers (`-- +goose Up/Down`) was discovered and fixed in 811025c.',
    :version,
    :author
);

-- ============================================================================
-- Slice 2 — Persistent sessions + cookie split (sid-bearing JWTs, kind-aware cookies)
-- ============================================================================
INSERT INTO version_log (id, environment, entry_type, title, description, version, created_by)
VALUES (
    gen_random_uuid(),
    :env,
    'security',
    'Persistent sessions + admin/user cookie split (revocable JWTs)',
    E'## What it does\n\nReplaces the prior signature-only JWT verification with a `sid` claim that ties every JWT to a row in a new `sessions` table. AuthMiddleware now validates the sid against Redis (60s TTL) → Postgres on cache miss, so revoking the row makes the JWT useless on the next API call. Also splits the auth cookie by user/admin context to prevent the long-standing problem where logging into admin would log out a parallel user session.\n\n## Why\n\n1. **Foundation for the Live Sessions admin page (Slice 4).** Without revocable sessions there is no "kick this user" capability.\n2. **Concurrent admin + user sessions.** Bryan was repeatedly being logged out of his parent UI by his admin login because both used `access_token`. Splitting cookies by kind fixes that.\n3. **8h JWT_ACCESS_EXPIRY default.** With silent refresh on the user side and now the admin side, the old 15m default was just generating noise.\n\n## Key changes\n\n- `internal/auth/perm.go`: `AuthClaims` gains `Sid uuid.UUID`.\n- `internal/middleware/auth.go`: `resolveCookieNames(path)` returns `[admin_access_token, access_token]` for admin paths and `[user_access_token, access_token]` otherwise; legacy `access_token` is the fallback so old browsers don''t log out at the moment of deploy.\n- `internal/service/auth_service.go`: `LoginWithContext` (kind/IP/UserAgent) creates a sessions row + sid-bearing token pair; `ValidateSession` / `TouchSession` / `RevokeSession` / `LogoutAdmin` / `LogoutAll` service surface.\n- `internal/repository/session_repo.go`: full CRUD on `sessions` (Create / GetByID / Revoke / RevokeForUserKind / TouchLastSeen / ListActive).\n- `internal/service/session_cache.go`: Redis cache namespaced under `session:sid:` to avoid colliding with the older `session:<userID>` helpers. 60s TTL for valid entries, 5m for revoked.\n- New endpoint `POST /api/auth/logout-all` (revokes every session for the user, all kinds).\n- `DELETE /api/admin/sessions/{sessionID}` (super_admin/support; partner added in Slice 3).\n- `stripPort()` helper in auth_service.go: strips `host:port` to just `host` before storing in the `sessions.ip` INET column. Without this, login 500s on Postgres ("value too long for type inet") because `r.RemoteAddr` includes the ephemeral port.\n\n## Migration\n\n00029 — drops the unused `user_sessions` table and creates the new `sessions` table with `session_kind` enum (`user`|`admin`).\n\n## Tests\n\n- `internal/repository/session_repo_test.go` — round-trip\n- `internal/service/session_cache_test.go` — miniredis-backed lookup/mark transitions\n- `internal/middleware/auth_test.go` — `resolveCookieNames` path → cookie-name table\n\n## Commits\n\ncba2019 → 3262c52 (~13 commits including design + plan + the stripPort hotfix).\n\n## Note on refresh + sid\n\nThe initial implementation called `generateTokens` from `RefreshToken`, which dropped the sid claim — making refreshed tokens unrevokable. That bug was fixed in commit 5eb43db (this same release) after it was caught during the admin-banner verification pass.',
    :version,
    :author
);

-- ============================================================================
-- Slice 3 — Partner role + matrix-driven permissions
-- ============================================================================
INSERT INTO version_log (id, environment, entry_type, title, description, version, created_by)
VALUES (
    gen_random_uuid(),
    :env,
    'feature',
    'Partner system role + matrix-driven admin permissions',
    E'## What it does\n\nAdds a fourth admin system role — `partner` — alongside `super_admin`, `support`, and `marketing`. Replaces the scattered ad-hoc role checks across the admin handlers with a single permission matrix (19 sections × 4 levels: none/read/write/full). Every per-section route group is now gated by `RequireSection("section_key")` middleware that consults the matrix; the sidebar uses matching `canSee` / `matrixLevel` template helpers so partners only see what their matrix row grants them.\n\n## Why\n\nPartner is meant to act as an emergency / sales-flow backup for Bryan: can kick sessions in an outage when Bryan isn''t at a computer (live_sessions=full), can issue atypical comps to qualified reviewers without waiting on Bryan (subscriptions=full, financials=full, family-subscriptions=full), but is locked out of system_settings, audit_log, and development_mode (those stay super_admin-only). Bryan-defined matrix.\n\n## Permission matrix (verbatim)\n\nSection                | super_admin | partner | support | marketing\n-----------------------|-------------|---------|---------|-----------\ndashboard              | full        | full    | full    | full\ntickets                | full        | full    | full    | none\nusers                  | full        | full    | full    | none\nfamilies               | full        | full    | full    | none\nlive_sessions         | full        | full    | full    | none\nmetrics_dashboard     | full        | full    | full    | none\ncopy_materials        | full        | read    | full    | full\nbeta_program          | full        | full    | full    | full\nbounty_program        | full        | read    | full    | full\npromo_codes           | full        | read    | full    | full\ninfrastructure_status | full        | read    | read    | none\nerror_logs            | full        | read    | full    | none\ndevelopment_mode      | full        | none    | none    | none\nproduct_roadmap       | full        | full    | full    | full\nfinancials            | full        | full    | none    | none\nsubscriptions         | full        | full    | none    | none\nadmin_users           | full        | read    | full    | none\nsystem_settings       | full        | none    | none    | none\naudit_log             | full        | none    | none    | none\nversion_log           | full        | read    | read    | read\n\n## Key changes\n\n- `internal/auth/perm.go` (NEW) → `Level` type (`none`/`read`/`write`/`full`), `Sections` list, `Matrix` map keyed by `(role, section)`, `Matrix(role, section)` lookup with super_admin short-circuit, `RequiredLevelForMethod` (GET→read, DELETE→full, others→write), `Allows(role, section, method)`.\n- `internal/middleware/section.go` (NEW) → `RequireSection(section)` middleware uses `RequiredLevelForMethod` to compute the level needed for THIS request and reject if the role''s matrix entry is below it.\n- `internal/handler/admin/routes.go` → restructured `/super`, `/support`, `/marketing` blocks into per-section `r.Group` calls each gated with `RequireSection`.\n- `internal/handler/admin/ui_handlers.go` → template funcs `canSee` and `matrixLevel`.\n- `templates/admin/layout.html` → sidebar items use `canSee` (visibility) and `matrixLevel` (read-only badge) so partners see exactly the sections their matrix row allows.\n- `cmd/seedadmin` → `createadmin` accepts `partner` as a valid role.\n\n## Migration\n\n00030 — `ALTER TYPE system_role ADD VALUE IF NOT EXISTS ''partner'';` (idempotent, no down-migration possible due to Postgres enum semantics — that''s acceptable).\n\n## Tests\n\n- `internal/auth/perm_test.go` — full matrix exercised including super_admin short-circuit and method-level mappings.\n- `internal/middleware/section_test.go` — RequireSection path coverage.\n\n## Commits\n\nd682c57 → 5d7d619 (~9 commits including design + plan).',
    :version,
    :author
);

-- ============================================================================
-- Slice 4 — Live Sessions admin page (cross-env display, same-env kill)
-- ============================================================================
INSERT INTO version_log (id, environment, entry_type, title, description, version, created_by)
VALUES (
    gen_random_uuid(),
    :env,
    'feature',
    'Live Sessions admin page — cross-env display + same-env kill',
    E'## What it does\n\nNew admin page at `/admin/sessions` that surfaces every active session — user JWT, admin JWT, and SSH — across BOTH environments. From the dev portal you see dev + prod (when `SESSIONS_PROD_DB_DSN` is configured); from prod you see prod only. Per-row "Revoke" button kills the session; cross-env rows show a disabled button with tooltip "Log into <env> admin to kill this session". Bulk-select + "Revoke selected" ships too. SSH section shows local env only (no SSH service runs on prod admin).\n\n## Why\n\n1. **Visibility** — for the first time we can see who is signed in right now, where, and on what kind.\n2. **Emergency kick** — partners (and super_admin/support) can boot a stuck session without sshing into the box.\n3. **Foundation for the admin logged-out banner** (Slice 5): the banner needs a "kicked" path to demonstrate.\n\n## Architecture\n\n- **Local-env JWT sessions** queried from `sessions` table (active, unrevoked, unexpired) — repo method `ListLive(ctx, kind, env)`.\n- **Cross-env JWT sessions** queried from a SECOND read-only Postgres pool opened from `SESSIONS_PROD_DB_DSN`. Failures (wrong creds, network unreachable, missing env var) render an inline notice — they do NOT 500 the page.\n- **Local SSH sessions** from existing `DevModeService.ListSSHSessions`. Wired into Live Sessions via late-binding `SetDevModeService` setter (DevModeService is constructed in main.go after the Services struct, so it can''t be passed at LiveSessionsService construction time).\n- **Why a second Postgres pool, not RPC** — matches the existing `SUPPORT_DB_DSN` pattern. No new auth layer. Read-only role on the prod side limits blast radius.\n- **Denormalized columns** on `sessions` (`user_email`, `user_first_name`, `user_last_name`, `family_name`, `env_name`) — written at login time by `LoginWithContext`. Necessary because direct cross-DB JOINs aren''t possible.\n\n## Authorization\n\nUI route + API endpoints all gated to super_admin / support / partner. UI uses `RequireSection("live_sessions")`; API uses inline `HasAnySystemRole` for parity with the existing single-session DELETE path.\n\n## API surface\n\n- `GET /api/admin/sessions/live` → JSON `{user, admin, ssh}` lists.\n- `POST /api/admin/sessions/revoke` body `{"ids":[...]}` → returns `{revoked: N}`. Accepts only same-env ids.\n- `POST /api/admin/sessions/ssh/kill` → kills an SSH session.\n- (`DELETE /api/admin/sessions/{sessionID}` already existed from Slice 2.)\n\n## Display\n\n- Env badge per row: blue `dev`, red `prod`.\n- Idle: rendered relative ("3m ago") from `last_seen_at`.\n- IP shown bare (sessions.ip is INET → `::text` cast in the repo).\n- User-agent truncated to 60 chars with full value in `title=`.\n- Auto-refresh: `window.location.reload()` every 30s; manual "Refresh" button.\n\n## Migration\n\n00031 — adds the 5 denorm columns to `sessions` and backfills existing rows via JOIN to `users` + `families`.\n\n## Cross-env config\n\nProd admin: keep `SESSIONS_PROD_DB_DSN` UNSET to keep the prod portal clean. Dev admin: set it to the prod RDS read-only role''s DSN to enable the cross-env section.\n\n## Tests\n\nManual integration on dev: kill round-trip (revoke from another browser → first browser sees 401 within 30s); cross-env display when DSN set; sidebar visibility per role.\n\n## Commits\n\nb2d3053 → e6cc659 (~10 commits including design + plan).',
    :version,
    :author
);

-- ============================================================================
-- Slice 5 — Admin logged-out banner + silent refresh
-- ============================================================================
INSERT INTO version_log (id, environment, entry_type, title, description, version, created_by)
VALUES (
    gen_random_uuid(),
    :env,
    'feature',
    'Admin logged-out banner + silent JWT refresh (mirrors user side)',
    E'## What it does\n\nWhen an admin is idle past their JWT expiry, or their session is revoked from another admin tab, they now see a graceful red sticky-top banner ("Your admin session has expired or been terminated. Sign in again to continue.") with a button that takes them back to `/admin/login?return=<previous-page>`. Behind the scenes:\n\n1. **Proactive silent refresh** — JS guard schedules a refresh ~5min before the access token would expire. The user never notices.\n2. **Reactive 401 retry** — wraps `window.fetch`. Any 401 on a guarded admin URL triggers a single-flight refresh + retry-once. Multiple parallel 401s collapse into one network call.\n3. **Banner only on real failure** — fires only when refresh itself fails (sid revoked OR refresh JWT expired/invalid). Idle expiry no longer surfaces a banner.\n\n## Why\n\nThe user-side `session_guard.js` had been live for weeks delivering this UX to parents. Admins were getting silent failures or unhelpful 401s when their tokens lapsed. Closes the gap.\n\n## Server changes\n\n- `internal/handler/admin/ui_handlers.go` → `AdminLoginSubmit` now sets a second cookie `admin_refresh_token` (Path=`/api/admin/auth/refresh`, 7d). `AdminLogout` clears it.\n- `internal/handler/admin/auth_handlers.go` (NEW) → `AdminRefreshToken` (public; reads admin_refresh_token cookie or JSON body; writes rotated cookies + JSON tokens) and `AdminAuthCheck` (auth-protected liveness probe → `{"valid":true}` 200 or 401 from middleware).\n- `internal/handler/admin/routes.go` → `GET /auth/check` inside the protected admin Routes().\n- `cmd/server/main.go` → `POST /api/admin/auth/refresh` mounted at the TOP LEVEL of the chi router, OUTSIDE the `/api/admin` Route block. (chi''s `Mount("/", adminHandler.Routes())` would otherwise intercept it via AuthMiddleware. This subtlety is documented in the route-registration comment.)\n\n## Sid-preservation hotfix\n\nDuring banner verification we discovered `RefreshToken` was calling `generateTokens` instead of `generateTokensWithSid` — refreshed tokens carried `Sid=uuid.Nil` and bypassed session validation entirely, meaning a revoked session could be kept alive indefinitely by hitting refresh. Fixed in commit 5eb43db: refresh now preserves the sid through `generateTokensWithSid`. Legacy pre-sid refresh tokens fall back to the original code path.\n\n## Client\n\n`static/js/admin_session_guard.js` (NEW, 196 lines) mirrors `static/js/session_guard.js` exactly — same IIFE shape, same single-flight pattern — but parameterized for admin cookies (`admin_access_token`), admin refresh endpoint (`/api/admin/auth/refresh`), admin login redirect (`/admin/login?return=...`), admin path predicate (`/api/admin/*` and `/admin/*` minus the auth endpoints themselves), and admin-specific banner copy.\n\n## Template\n\n`templates/admin/layout.html` includes the script in `<head>` (synchronous, after the Tailwind CDN). Critical: NOT at end-of-body. Some admin subpages (e.g. `subscriptions.html`) issue parse-time fetches; if the guard installs after them, those calls bypass the wrapper.\n\n## Tests\n\n- `internal/handler/admin/auth_handlers_test.go` — 3 input-parsing cases (no cookie/body → 400, garbage body → 400, empty refresh field → 400).\n- Manual integration on dev: full login → check → refresh → revoke → check 401 round-trip verified end-to-end.\n\n## Coexistence\n\nThe user-side `session_guard.js` is NOT loaded on admin pages today — confirmed by inspecting admin layout.html — so the two guards do not fight over `window.fetch`.\n\n## Commits\n\n79ae3e2 → 5eb43db (12 commits including design + plan + the sid-preservation hotfix).',
    :version,
    :author
);

-- ============================================================================
-- Pre-slice UI fixes (rolled into the same release)
-- ============================================================================
INSERT INTO version_log (id, environment, entry_type, title, description, version, created_by)
VALUES (
    gen_random_uuid(),
    :env,
    'bugfix',
    'Parent UI bug fixes — dashboard, seizure log, support triage',
    E'## What it does\n\nFolds in 7 small bug fixes that landed on dev between the 2026-05-07 ship and the start of the persistent-sessions slice. None warranted a standalone release; bundled here for traceability.\n\n## Fixes\n\n- `4110048` fix(support-triage): med-interaction timeout, chat thread auto-select, mascot reopen, reports back button.\n- `0762b61` chore(claude): project-scope enforcement + GSD plugin disabled in this repo (Claude Code config; no runtime impact).\n- `d503d05` fix(dashboard): bright-spot meds % was 100x too high and triggered too often (off-by-100x; division/percent confusion).\n- `ea07a95` fix(child-dashboard): "At a glance" header overflowed off the right on mobile narrow viewports.\n- `90bf9d3` fix(seizure-log): blank time field returns 400 instead of 500 (validation runs before DB insert).\n- `281535d` fix(child-dashboard): require Time field on the dashboard seizure quick-log form (matches the full form).\n- `cadb14b` fix(auth): bump JWT_ACCESS_EXPIRY default 15m → 8h (paired with silent refresh on user/admin sides — minimizes unnecessary refresh churn).\n\n## Tests\n\nEach fix verified manually on dev. None of these touched migrations or auth boundaries.',
    :version,
    :author
);

COMMIT;
